\[
  \forall X, Y \subseteq \mathbb{R}:\quad
  \begin{cases}
    \forall x \in X,\; x \in \overline{X} \\
    \overline{X \cup Y} = \overline{X} \cup \overline{Y} \\
    \forall x \in \overline{X \cap Y},\;
      x \in \overline{X} \cap \overline{Y} \\
    X \subseteq Y \;\Rightarrow\;
      \forall x \in \overline{X},\; x \in \overline{Y}
  \end{cases}
\]

\[
  c \text{ is a cluster point of } A
  \;\iff\;
  \exists (a_n)_{n=1}^\infty \subseteq A \setminus \{c\},\;
  \lim_{n \to \infty} a_n = c.
\]

\[
  \bigl[X \text{ closed} \wedge X \text{ bounded}\bigr]
  \;\iff\;
  \forall (a_n) \subseteq X,\;
  \exists (a_{n_j}),\;
  \exists L \in X,\;
  a_{n_j} \to L.
\]

\[
  \forall X \subseteq \mathbb{R},\;
  \forall x \in \mathbb{R},\;
  \Bigl[
    x \in \overline{X}
    \;\iff\;
    \forall \varepsilon > 0,\;
    \exists\, y \in X,\;
    |x - y| \leq \varepsilon
  \Bigr].
\]

\[
  \forall E \subseteq \mathbb{R},\;
  \Bigl[
    E \text{ is closed}
    \;\iff\;
    \forall x \in \mathbb{R},\;
    \Bigl(
      \forall \varepsilon > 0,\;
      \exists\, y \in E,\;
      |x - y| \leq \varepsilon
      \;\Rightarrow\;
      x \in E
    \Bigr)
  \Bigr].
\]
